import java.util.Arrays;

public int maxValue(int[][] events) {
    Arrays.sort(events, (a, b) -> Integer.compare(a[1], b[1]));

    int[] dp = new int[events.length];
    dp[0] = events[0][2];

    for (int i = 1; i < events.length; i++) {
        int lastNonConflict = -1;
        for (int j = i - 1; j >= 0; j--) {
            if (events[j][1] < events[i][0]) {
                lastNonConflict = j;
                break;
            }
        }

        int includedValue = events[i][2];
        if (lastNonConflict != -1) {
            includedValue += dp[lastNonConflict];
        }

        dp[i] = Math.max(includedValue, dp[i - 1]);
    }

    return dp[dp.length - 1];
}
```

